#include <stdio.h>
int main(){
    int T;
    scanf("%d", &T);
    while(T--){
        long long X;
        scanf("%lld", &X);
        if(X & 1LL) printf("-1 -1 -1\n");
        else{
            long long Y = X/2;
            printf("0 %lld %lld\n", Y, Y);
        }
    }
    return 0;
}

